const db = require('../src/db');
const migrations = require('../src/migrations');

describe('Database Migrations', () => {
  test('should create users table', async () => {
    await migrations.createUsersTable();
    const result = await db.query('SELECT * FROM users');
    expect(result).toBeDefined();
  });

  test('should add email column', async () => {
    await migrations.addEmailColumn();
    const result = await db.query("SELECT column_name FROM information_schema.columns WHERE table_name='users' AND column_name='email'");
    expect(result.rows.length).toBe(1);
  });

  test('should create index on email', async () => {
    await migrations.createEmailIndex();
    const result = await db.query("SELECT indexname FROM pg_indexes WHERE indexname='idx_users_email'");
    expect(result.rows.length).toBe(1);
  });

  test('should add unique constraint', async () => {
    await migrations.addUniqueConstraint();
    const result = await db.query("SELECT constraint_name FROM information_schema.table_constraints WHERE constraint_name='users_email_key'");
    expect(result.rows.length).toBe(1);
  });
});

const db = require('./db');

async function createUsersTable() {
  await db.query('CREATE TABLE users (id SERIAL PRIMARY KEY, name VARCHAR(255))');
}

async function addEmailColumn() {
  await db.query('ALTER TABLE users ADD COLUMN email VARCHAR(255)');
}

async function createEmailIndex() {
  await db.query('CREATE INDEX idx_users_email ON users(email)');
}

async function addUniqueConstraint() {
  await db.query('ALTER TABLE users ADD CONSTRAINT users_email_key UNIQUE (email)');
}

module.exports = {
  createUsersTable,
  addEmailColumn,
  createEmailIndex,
  addUniqueConstraint
};
